    url = f"{RABBITMQ_API_URL}/permissions/{vhost_name}/{username}"
    payload = {
        "configure": configure,
        "read": read,
        "write": write
    }
    response = requests.put(url, auth=(USERNAME, PASSWORD), json=payload)
